class Counter {
    static total: int = 0
    static instances: int = 0
    static maxAllowed: int = 100
    static defaultStep: int = 1

    public id: int
    public count: int = 0
    public step: int
    private _active: bool = true
    protected _multiplier: int

    constructor(id: int, step: int, multiplier: int) {
        this.id = id
        this.step = step
        this._multiplier = multiplier
        this.count = id * step - multiplier
        Counter.total = Counter.total + this.count
        Counter.instances = Counter.instances + 1
    }

    static getTotal(): int {
        return Counter.total
    }

    static getInstance(): int {
        return Counter.instances
    }

    static isOverLimit(): bool {
        return Counter.instances >= Counter.maxAllowed && Counter.total > 0
    }

    static reset() {
        Counter.total = 0
        Counter.instances = 0
    }

    static computeGlobal(factor: int): int {
        return Counter.total * factor - Counter.instances * Counter.defaultStep + Counter.maxAllowed
    }

    increment(): int {
        val prev = this.count
        this.count = this.count + this.step * this._multiplier
        Counter.total = Counter.total + this.count - prev
        return this.count
    }

    decrement(): int {
        val prev = this.count
        this.count = this.count - this.step
        Counter.total = Counter.total - (prev - this.count)
        return this.count
    }

    reset() {
        Counter.total = Counter.total - this.count
        this.count = 0
    }

    getScore(): int {
        return this.count * this._multiplier - this.step * Counter.defaultStep + Counter.getTotal()
    }

    isActive(): bool {
        return this._active && this.count >= 0 && !Counter.isOverLimit()
    }
}

class RangedCounter extends Counter {
    public min: int
    public max: int
    static rangedInstances: int = 0
    static rangedTotal: int = 0

    constructor(id: int, step: int, multiplier: int, min: int, max: int) {
        super(id, step, multiplier)
        this.min = min
        this.max = max
        this.count = min + id * step - multiplier
        RangedCounter.rangedInstances = RangedCounter.rangedInstances + 1
        RangedCounter.rangedTotal = RangedCounter.rangedTotal + this.count
    }

    static getRangedTotal(): int {
        return RangedCounter.rangedTotal + Counter.getTotal()
    }

    static isRangedOverLimit(): bool {
        return RangedCounter.rangedInstances >= Counter.maxAllowed || Counter.isOverLimit()
    }

    clamp(): int {
        if (this.count < this.min) {
            val diff = this.min - this.count
            Counter.total = Counter.total + diff
            RangedCounter.rangedTotal = RangedCounter.rangedTotal + diff
            this.count = this.min
        }
        if (this.count > this.max) {
            val diff = this.count - this.max
            Counter.total = Counter.total - diff
            RangedCounter.rangedTotal = RangedCounter.rangedTotal - diff
            this.count = this.max
        }
        return this.count
    }

    getScore(): int {
        val base = this.count * this.max - this.min * this.step
        val globalFactor = Counter.getTotal() * RangedCounter.getRangedTotal()
        return base + globalFactor - Counter.computeGlobal(this._multiplier)
    }

    isInRange(): bool {
        return this.count >= this.min && this.count <= this.max && this.isActive()
    }
}

